80	const itemSurchargeMultsPct = (item: Item): number[] => {
81	  const mults: number[] = [];
82	  if (item.cursed) mults.push(CURSED_MULT_PCT);
83	  if (isHighlyEnchanted(item)) mults.push(HIGHLY_ENCHANTED_MULT_PCT);
84	  return mults;
85	};
86	
87	const stepMultsPct = (
88	  customer: Customer | undefined,
89	  stepIndex: number,
90	): number[] => {
91	  if (isAfterFirstStep(stepIndex)) return [AFTER_FIRST_MULT_PCT];
92	  const mults: number[] = [];
93	  if (hasLoyalty(customer)) mults.push(LOYALTY_MULT_PCT);
94	  mults.push(FIRST_CONTRACT_MULT_PCT);
95	  return mults;
96	};
97	
98	const applyMultsAndFee = (base: number, multsPct: number[]): number => {
99	  const numerator = multsPct.reduce((n, m) => n * m, base);
100	  const denominator = Math.pow(PERCENT_SCALE, multsPct.length);
101	  return Math.ceil(numerator / denominator) + PROCESSING_FEE;
102	};
103	
104	const quoteStep = (
105	  step: Step,
106	  stepIndex: number,
107	  customer: Customer | undefined,
108	): ScenarioResult => {
109	  const multsPct = [
110	    ...itemSurchargeMultsPct(step.items[0]),
111	    ...stepMultsPct(customer, stepIndex),
112	  ];
113	  return { premium: applyMultsAndFee(stepBase(step), multsPct) };
114	};
115	
116	const CLAIM_DEDUCTIBLE = 100;
117	const DRAGON_REIMBURSEMENT_RATE_PCT = 100;
118	const HIGHLY_ENCHANTED_REIMBURSEMENT_RATE_PCT = 50;
119	const CLAIM_HIGHLY_ENCHANTED_MIN = 8;
120	
121	const isHighlyEnchantedForClaim = (item: Item): boolean =>
122	  (item.enchantment ?? 0) >= CLAIM_HIGHLY_ENCHANTED_MIN;
123	
124	const reimbursementRatePct = (item: Item | undefined): number => {
125	  if (!item) return 0;
126	  const rates: number[] = [0];
127	  if (item.material === "dragon") rates.push(DRAGON_REIMBURSEMENT_RATE_PCT);
128	  if (isHighlyEnchantedForClaim(item))
129	    rates.push(HIGHLY_ENCHANTED_REIMBURSEMENT_RATE_PCT);
130	  return Math.max(...rates);
131	};
132	
133	const damageReimbursement = (damage: Damage, policyStep: Step): number => {
134	  const item = policyStep.items.find((i) => i.type === damage.itemType);
135	  return (damage.amount * reimbursementRatePct(item)) / PERCENT_SCALE;
136	};
137	
138	const payoutAfterDeductible = (grossReimbursable: number): number =>
139	  Math.max(0, grossReimbursable - CLAIM_DEDUCTIBLE);
140	
141	const claimStep = (step: Step, steps: Step[]): ScenarioResult => {
142	  const policyStep = steps[step.policy ?? 0];
143	  const grossReimbursable = (step.incident?.damages ?? []).reduce(
144	    (sum, damage) => sum + damageReimbursement(damage, policyStep),
145	    0,
146	  );
147	  return { payout: payoutAfterDeductible(grossReimbursable) };
148	};
149	
150	export function runScenario(input: unknown): ScenarioOutput {
151	  const { customer, steps } = input as Input;
152	  const results = steps.map((step, stepIndex) =>
153	    step.op === "claim"
154	      ? claimStep(step, steps)
155	      : quoteStep(step, stepIndex, customer),
156	  );
157	  return { results };
158	}
